  1→use std::{collections::HashMap, net::SocketAddr, sync::Arc};
  2→
  3→use {
  4→    axum::extract::ws::{Message, WebSocket},
  5→    futures::{SinkExt, stream::StreamExt},
  6→    tokio::sync::mpsc,
  7→    tracing::{debug, info, warn},
  8→};
  9→
 10→use moltis_protocol::{
 11→    ConnectParams, ConnectParamsV4, ErrorShape, EventFrame, Extensions, Features, GatewayFrame,
 12→    HANDSHAKE_TIMEOUT_MS, HelloAuth, HelloOk, KNOWN_EVENTS, MAX_PAYLOAD_BYTES, PROTOCOL_VERSION,
 13→    Policy, ResponseFrame, ServerInfo, error_codes, roles, scopes,
 14→};
 15→
 16→use moltis_gateway::{
 17→    auth,
 18→    broadcast::{BroadcastOpts, broadcast},
 19→    methods::{MethodContext, MethodRegistry},
 20→    nodes::NodeSession,
 21→    state::{ConnectedClient, GatewayState},
 22→};
 23→
 24→fn top_level_param_keys(params: &Option<serde_json::Value>) -> Vec<String> {
 25→    params
 26→        .as_ref()
 27→        .and_then(serde_json::Value::as_object)
 28→        .map(|obj| obj.keys().cloned().collect())
 29→        .unwrap_or_default()
 30→}
 31→
 32→/// Handle a single WebSocket connection through its full lifecycle:
 33→/// handshake (with auth) → message loop → cleanup.
 34→pub async fn handle_connection(
 35→    socket: WebSocket,
 36→    state: Arc<GatewayState>,
 37→    methods: Arc<MethodRegistry>,
 38→    remote_addr: SocketAddr,
 39→    accept_language: Option<String>,
 40→    remote_ip: Option<String>,
 41→    header_authenticated: bool,
 42→    is_local: bool,
 43→) {
 44→    let conn_id = uuid::Uuid::new_v4().to_string();
 45→    let conn_remote_ip = remote_addr.ip().to_string();
 46→    info!(conn_id = %conn_id, remote_ip = %conn_remote_ip, "ws: new connection");
 47→
 48→    let (mut ws_tx, mut ws_rx) = socket.split();
 49→    // Bounded channel prevents unbounded memory growth from slow clients.
 50→    let (client_tx, mut client_rx) = mpsc::channel::<String>(512);
 51→
 52→    // Spawn write loop: forwards frames from the client_tx channel to the WebSocket.
 53→    let write_conn_id = conn_id.clone();
 54→    let write_handle = tokio::spawn(async move {
 55→        while let Some(msg) = client_rx.recv().await {
 56→            if ws_tx.send(Message::Text(msg.into())).await.is_err() {
 57→                debug!(conn_id = %write_conn_id, "ws: write loop closed");
 58→                break;
 59→            }
 60→        }
 61→    });
 62→
 63→    // ── Handshake phase ──────────────────────────────────────────────────
 64→
 65→    let connect_result = match tokio::time::timeout(
 66→        std::time::Duration::from_millis(HANDSHAKE_TIMEOUT_MS),
 67→        wait_for_connect(&mut ws_rx),
 68→    )
 69→    .await
 70→    {
 71→        Ok(Ok(result)) => result,
 72→        Ok(Err(e)) => {
 73→            warn!(conn_id = %conn_id, error = %e, "ws: handshake failed");
 74→            graceful_writer_shutdown(client_tx, write_handle).await;
 75→            return;
 76→        },
 77→        Err(_) => {
 78→            warn!(conn_id = %conn_id, "ws: handshake timeout");
 79→            graceful_writer_shutdown(client_tx, write_handle).await;
 80→            return;
 81→        },
 82→    };
 83→
 84→    let ConnectResult {
 85→        request_id,
 86→        params,
 87→        is_v4,
 88→    } = connect_result;
 89→
 90→    if state.ws_request_logs {
 91→        let connect_param_keys = serde_json::to_value(&params)
 92→            .ok()
 93→            .and_then(|v| v.as_object().cloned())
 94→            .map(|obj| obj.keys().cloned().collect::<Vec<_>>())
 95→            .unwrap_or_default();
 96→        info!(
 97→            conn_id = %conn_id,
 98→            request_id = %request_id,
 99→            method = "connect",
100→            param_keys = ?connect_param_keys,
101→            "ws: received request frame"
102→        );
103→    }
104→
105→    // Validate protocol version.
106→    if params.min_protocol > PROTOCOL_VERSION || params.max_protocol < PROTOCOL_VERSION {
107→        warn!(
108→            conn_id = %conn_id,
109→            min_protocol = params.min_protocol,
110→            max_protocol = params.max_protocol,
111→            server_protocol = PROTOCOL_VERSION,
112→            "ws: protocol mismatch"
113→        );
114→        let err = ResponseFrame::err(
115→            &request_id,
116→            ErrorShape::new(
117→                error_codes::PROTOCOL_ERROR,
118→                format!(
119→                    "protocol mismatch: server={}, client={}-{}",
120→                    PROTOCOL_VERSION, params.min_protocol, params.max_protocol
121→                ),
122→            ),
123→        );
124→        #[allow(clippy::unwrap_used)] // serializing known-valid struct
125→        let _ = client_tx.try_send(serde_json::to_string(&err).unwrap());
126→        graceful_writer_shutdown(client_tx, write_handle).await;
127→        return;
128→    }
129→
130→    // ── Auth validation ──────────────────────────────────────────────────
131→    // SECURITY: Three-tier auth model (see docs/src/security.md):
132→    //
133→    // 1. Password set → always require credentials, any IP.
134→    // 2. No password + genuine local connection → full access (dev convenience).
135→    // 3. No password + remote/proxied → onboarding only.
136→    //
137→    // `is_local` is computed per-request by `is_local_connection()` using:
138→    //   - MOLTIS_BEHIND_PROXY env var (hard override)
139→    //   - Proxy header detection (X-Forwarded-For, X-Real-IP, etc.)
140→    //   - Host header loopback check
141→    //   - TCP source IP loopback check
142→    //
143→    // See CVE-2026-25253 for the analogous OpenClaw vulnerability.
144→    let mut authenticated = header_authenticated;
145→    // Scopes from API key verification (if any).
146→    let mut api_key_scopes: Option<Vec<String>> = None;
147→    // Device token verification result (if any).
148→    let mut device_token_device_id: Option<String> = None;
149→
150→    // Check device token first (used by paired nodes).
151→    if !authenticated
152→        && let Some(ref dt) = params.auth.as_ref().and_then(|a| a.device_token.clone())
153→        && let Some(ref store) = state.pairing_store
154→    {
155→        match store.verify_device_token(dt).await {
156→            Ok(Some(verification)) => {
157→                authenticated = true;
158→                api_key_scopes = Some(verification.scopes.clone());
159→                device_token_device_id = Some(verification.device_id.clone());
160→                info!(
161→                    conn_id = %conn_id,
162→                    device_id = %verification.device_id,
163→                    "ws: authenticated via device token"
164→                );
165→            },
166→            Ok(None) => {
167→                debug!(conn_id = %conn_id, "ws: device token not found or revoked");
168→            },
169→            Err(e) => {
170→                debug!(conn_id = %conn_id, error = %e, "ws: device token verification failed");
171→            },
172→        }
173→    }
174→
175→    if !authenticated && let Some(ref cred_store) = state.credential_store {
176→        if cred_store.is_setup_complete() {
177→            // Check API key.
178→            if let Some(ref api_key) = params.auth.as_ref().and_then(|a| a.api_key.clone())
179→                && let Ok(Some(verification)) = cred_store.verify_api_key(api_key).await
180→            {
181→                authenticated = true;
182→                // Store the scopes from the API key (empty = no access)
183→                api_key_scopes = Some(verification.scopes);
184→            }
185→            // Check password against DB hash.
186→            if !authenticated
187→                && let Some(ref pw) = params.auth.as_ref().and_then(|a| a.password.clone())
188→                && cred_store.verify_password(pw).await.unwrap_or(false)
189→            {
190→                authenticated = true;
191→            }
192→        } else {
193→            // Setup not complete yet — only allow local connections.
194→            // Remote connections must go through the onboarding/setup flow.
195→            if is_local {
196→                authenticated = true;
197→            }
198→        }
199→    }
200→
201→    // Fall back to legacy env-var auth if credential store didn't authenticate.
202→    if !authenticated {
203→        let has_legacy_auth = state.auth.token.is_some() || state.auth.password.is_some();
204→        if has_legacy_auth {
205→            let provided_token = params.auth.as_ref().and_then(|a| a.token.as_deref());
206→            let provided_password = params.auth.as_ref().and_then(|a| a.password.as_deref());
207→            let auth_result = auth::authorize_connect(
208→                &state.auth,
209→                provided_token,
210→                provided_password,
211→                Some(&conn_remote_ip),
212→            );
213→            if auth_result.ok {
214→                authenticated = true;
215→            }
216→        } else if state.credential_store.is_none() {
217→            // No auth configured at all — grant access (backward compat).
218→            authenticated = true;
219→        }
220→    }
221→
222→    if !authenticated {
223→        let setup_complete = state
224→            .credential_store
225→            .as_ref()
226→            .is_some_and(|store| store.is_setup_complete());
227→        let has_api_key = params
228→            .auth
229→            .as_ref()
230→            .and_then(|auth| auth.api_key.as_ref())
231→            .is_some();
232→        let has_password = params
233→            .auth
234→            .as_ref()
235→            .and_then(|auth| auth.password.as_ref())
236→            .is_some();
237→        let has_token = params
238→            .auth
239→            .as_ref()
240→            .and_then(|auth| auth.token.as_ref())
241→            .is_some();
242→        warn!(
243→            conn_id = %conn_id,
244→            is_local,
245→            header_authenticated,
246→            setup_complete,
247→            has_api_key,
248→            has_password,
249→            has_token,
250→            "ws: auth failed"
251→        );
252→        let err = ResponseFrame::err(
253→            &request_id,
254→            ErrorShape::new(error_codes::UNAUTHORIZED, "authentication failed"),
255→        );
256→        #[allow(clippy::unwrap_used)] // serializing known-valid struct
257→        let _ = client_tx.try_send(serde_json::to_string(&err).unwrap());
258→        graceful_writer_shutdown(client_tx, write_handle).await;
259→        return;
260→    }
261→
262→    // Device-token-authenticated connections default to "node" role.
263→    let role = if device_token_device_id.is_some() {
264→        params.role.clone().unwrap_or_else(|| roles::NODE.into())
265→    } else {
266→        params
267→            .role
268→            .clone()
269→            .unwrap_or_else(|| roles::OPERATOR.into())
270→    };
271→
272→    // Determine scopes based on auth method.
273→    // API keys MUST declare scopes explicitly — empty scopes means no access.
274→    // Non-API-key auth (password, local, legacy) gets full access.
275→    let scopes = match api_key_scopes {
276→        Some(key_scopes) if !key_scopes.is_empty() => key_scopes,
277→        Some(_empty) => {
278→            // API key with no scopes → reject (least-privilege).
279→            warn!(conn_id = %conn_id, "ws: API key has no scopes, denying access");
280→            let err = ResponseFrame::err(
281→                &request_id,
282→                ErrorShape::new(
283→                    error_codes::FORBIDDEN,
284→                    "API key has no scopes — specify at least one scope when creating the key",
285→                ),
286→            );
287→            #[allow(clippy::unwrap_used)] // serializing known-valid struct
288→            let _ = client_tx.try_send(serde_json::to_string(&err).unwrap());
289→            graceful_writer_shutdown(client_tx, write_handle).await;
290→            return;
291→        },
292→        None => {
293→            // Non-API-key auth (password, local, legacy) → full access.
294→            vec![
295→                scopes::ADMIN.into(),
296→                scopes::READ.into(),
297→                scopes::WRITE.into(),
298→                scopes::APPROVALS.into(),
299→                scopes::PAIRING.into(),
300→            ]
301→        },
302→    };
303→
304→    // Build HelloOk with auth info.
305→    let hello_auth = HelloAuth {
306→        device_token: String::new(),
307→        role: role.clone(),
308→        scopes: scopes.clone(),
309→        issued_at_ms: Some(
310→            std::time::SystemTime::now()
311→                .duration_since(std::time::UNIX_EPOCH)
312→                .unwrap_or_default()
313→                .as_millis() as u64,
314→        ),
315→    };
316→
317→    let hello = HelloOk {
318→        r#type: "hello-ok".into(),
319→        protocol: PROTOCOL_VERSION,
320→        server: ServerInfo {
321→            version: state.version.clone(),
322→            commit: None,
323→            host: Some(state.hostname.clone()),
324→            conn_id: conn_id.clone(),
325→        },
326→        features: Features {
327→            methods: methods.method_names(),
328→            events: KNOWN_EVENTS.iter().map(|s| (*s).into()).collect(),
329→        },
330→        snapshot: serde_json::json!({}),
331→        canvas_host_url: None,
332→        auth: Some(hello_auth),
333→        policy: Policy::default(),
334→        extensions: Extensions::new(),
335→    };
336→    #[allow(clippy::unwrap_used)] // serializing known-valid struct
337→    let hello_val = serde_json::to_value(&hello).unwrap();
338→    let resp = ResponseFrame::ok(&request_id, hello_val);
339→    #[allow(clippy::unwrap_used)] // serializing known-valid struct
340→    let _ = client_tx.try_send(serde_json::to_string(&resp).unwrap());
341→
342→    info!(
343→        conn_id = %conn_id,
344→        client_id = %params.client.id,
345→        client_version = %params.client.version,
346→        role = %role,
347→        "ws: handshake complete"
348→    );
349→
350→    // Register the client with server-resolved scopes so broadcast guards work.
351→    let now = std::time::Instant::now();
352→    let mut resolved_params = params.clone();
353→    resolved_params.scopes = Some(scopes.clone());
354→    resolved_params.role = Some(role.clone());
355→    let browser_timezone = params.timezone.clone();
356→
357→    // Auto-persist browser timezone to USER.md on first connect (one-time).
358→    if let Some(ref tz_str) = browser_timezone
359→        && let Ok(tz) = tz_str.parse::<chrono_tz::Tz>()
360→    {
361→        let existing_user = moltis_config::load_user();
362→        if existing_user
363→            .as_ref()
364→            .and_then(|u| u.timezone.as_ref())
365→            .is_none()
366→        {
367→            let mut user = existing_user.unwrap_or_default();
368→            user.timezone = Some(moltis_config::Timezone::from(tz));
369→            if let Err(e) = moltis_config::save_user(&user) {
370→                warn!(conn_id = %conn_id, error = %e, "ws: failed to auto-persist timezone");
371→            } else {
372→                info!(conn_id = %conn_id, timezone = %tz_str, "ws: auto-persisted browser timezone to USER.md");
373→            }
374→        }
375→    }
376→
377→    // v3 clients default to wildcard subscriptions (all events).
378→    // v4 clients default to empty subscriptions (must explicitly subscribe).
379→    let subscriptions = if is_v4 {
380→        Some(std::collections::HashSet::new())
381→    } else {
382→        None
383→    };
384→
385→    let client = ConnectedClient {
386→        conn_id: conn_id.clone(),
387→        connect_params: resolved_params,
388→        sender: client_tx.clone(),
389→        connected_at: now,
390→        last_activity: now,
391→        accept_language,
392→        remote_ip,
393→        timezone: browser_timezone,
394→        subscriptions,
395→        joined_channels: std::collections::HashSet::new(),
396→        negotiated_protocol: PROTOCOL_VERSION,
397→    };
398→    state.register_client(client).await;
399→
400→    #[cfg(feature = "metrics")]
401→    {
402→        moltis_metrics::counter!(moltis_metrics::websocket::CONNECTIONS_TOTAL).increment(1);
403→        moltis_metrics::gauge!(moltis_metrics::websocket::CONNECTIONS_ACTIVE).increment(1.0);
404→    }
405→
406→    // If node role, register in node registry.
407→    if role == roles::NODE {
408→        let caps = params.caps.clone().unwrap_or_default();
409→        let commands = params.commands.clone().unwrap_or_default();
410→        let permissions: HashMap<String, bool> = params
411→            .permissions
412→            .as_ref()
413→            .map(|m| {
414→                m.iter()
415→                    .filter_map(|(k, v)| v.as_bool().map(|b| (k.clone(), b)))
416→                    .collect()
417→            })
418→            .unwrap_or_default();
419→
420→        let node = NodeSession {
421→            node_id: params.client.id.clone(),
422→            conn_id: conn_id.clone(),
423→            display_name: params.client.display_name.clone(),
424→            platform: params.client.platform.clone(),
425→            version: params.client.version.clone(),
426→            capabilities: caps,
427→            commands,
428→            permissions,
429→            path_env: params.path_env.clone(),
430→            remote_ip: Some(conn_remote_ip.clone()),
431→            connected_at: now,
432→            mem_total: None,
433→            mem_available: None,
434→            cpu_count: None,
435→            cpu_usage: None,
436→            uptime_secs: None,
437→            services: Vec::new(),
438→            last_telemetry: None,
439→            disk_total: None,
440→            disk_available: None,
441→            runtimes: Vec::new(),
442→            providers: Vec::new(),
443→        };
444→        state.inner.write().await.nodes.register(node);
445→        info!(conn_id = %conn_id, node_id = %params.client.id, "node registered");
446→
447→        // Broadcast presence change.
448→        broadcast(
449→            &state,
450→            "presence",
451→            serde_json::json!({
452→                "type": "node.connected",
453→                "nodeId": params.client.id,
454→                "platform": params.client.platform,
455→            }),
456→            BroadcastOpts::default(),
457→        )
458→        .await;
