542→                warn!(conn_id = %conn_id, error = %e, "ws: invalid frame");
543→                let err = EventFrame::new(
544→                    "error",
545→                    serde_json::json!({ "message": "invalid frame" }),
546→                    state.next_seq(),
547→                );
548→                #[allow(clippy::unwrap_used)] // serializing known-valid struct
549→                let _ = client_tx.try_send(serde_json::to_string(&err).unwrap());
550→                continue;
551→            },
552→        };
553→
554→        // Touch activity timestamp.
555→        if let Some(client) = state.inner.write().await.clients.get_mut(&conn_id) {
556→            client.touch();
557→        }
558→
559→        match frame {
560→            GatewayFrame::Request(req) => {
561→                if state.ws_request_logs {
562→                    info!(
563→                        conn_id = %conn_id,
564→                        request_id = %req.id,
565→                        method = %req.method,
566→                        param_keys = ?top_level_param_keys(&req.params),
567→                        "ws: received request frame"
568→                    );
569→                }
570→                let ctx = MethodContext {
571→                    request_id: req.id.clone(),
572→                    method: req.method.clone(),
573→                    params: req.params.unwrap_or(serde_json::Value::Null),
574→                    client_conn_id: conn_id.clone(),
575→                    client_role: role.clone(),
576→                    client_scopes: scopes.clone(),
577→                    state: Arc::clone(&state),
578→                    channel: req.channel,
579→                };
580→                let response = methods.dispatch(ctx).await;
581→                if state.ws_request_logs {
582→                    info!(
583→                        conn_id = %conn_id,
584→                        request_id = %req.id,
585→                        method = %req.method,
586→                        ok = response.ok,
587→                        "ws: sent response frame"
588→                    );
589→                }
590→                #[allow(clippy::unwrap_used)] // serializing known-valid struct
591→                let _ = client_tx.try_send(serde_json::to_string(&response).unwrap());
592→            },
593→            GatewayFrame::Response(res) => {
594→                // v4 bidirectional RPC: client responding to a server-initiated request.
595→                let pending = state
596→                    .inner
597→                    .write()
598→                    .await
599→                    .pending_client_requests
600→                    .remove(&res.id);
601→                if let Some(req) = pending {
602→                    let result = if res.ok {
603→                        Ok(res.payload.unwrap_or(serde_json::Value::Null))
604→                    } else {
605→                        Err(res.error.unwrap_or_else(|| {
606→                            ErrorShape::new(
607→                                error_codes::INTERNAL,
608→                                "client returned error without details",
609→                            )
610→                        }))
611→                    };
612→                    let _ = req.sender.send(result);
613→                } else {
614→                    debug!(conn_id = %conn_id, id = %res.id, "ws: response for unknown request");
615→                }
616→            },
617→            _ => {
618→                debug!(conn_id = %conn_id, "ws: ignoring non-request frame");
619→            },
620→        }
621→    }
622→
623→    // ── Cleanup ──────────────────────────────────────────────────────────
624→
625→    // Unregister node if applicable.
626→    let removed_node = state.inner.write().await.nodes.unregister_by_conn(&conn_id);
627→    if let Some(node) = &removed_node {
628→        info!(conn_id = %conn_id, node_id = %node.node_id, "node unregistered");
629→        broadcast(
630→            &state,
631→            "presence",
632→            serde_json::json!({
633→                "type": "node.disconnected",
634→                "nodeId": node.node_id,
635→            }),
636→            BroadcastOpts::default(),
637→        )
638→        .await;
639→    }
640→
641→    let duration = state
642→        .remove_client(&conn_id)
643→        .await
644→        .map(|c| c.connected_at.elapsed())
645→        .unwrap_or_default();
646→
647→    #[cfg(feature = "metrics")]
648→    moltis_metrics::gauge!(moltis_metrics::websocket::CONNECTIONS_ACTIVE).decrement(1.0);
649→
650→    info!(
651→        conn_id = %conn_id,
652→        duration_secs = duration.as_secs(),
653→        "ws: connection closed"
654→    );
655→
656→    drop(client_tx);
657→    write_handle.abort();
658→}
659→
660→/// Result of parsing connect params: includes whether v4 format was used.
661→struct ConnectResult {
662→    request_id: String,
663→    params: ConnectParams,
664→    is_v4: bool,
665→}
666→
667→async fn graceful_writer_shutdown(
668→    client_tx: mpsc::Sender<String>,
669→    write_handle: tokio::task::JoinHandle<()>,
670→) {
671→    drop(client_tx);
672→    let _ = tokio::time::timeout(std::time::Duration::from_millis(200), write_handle).await;
673→}
674→
675→/// Wait for the first `connect` request frame. Tries v4 format first, falls back to v3.
676→async fn wait_for_connect(
677→    rx: &mut futures::stream::SplitStream<WebSocket>,
678→) -> anyhow::Result<ConnectResult> {
679→    while let Some(msg) = rx.next().await {
680→        let text = match msg? {
681→            Message::Text(t) => t.to_string(),
682→            Message::Close(_) => anyhow::bail!("connection closed before handshake"),
683→            _ => continue,
684→        };
685→
686→        let frame: GatewayFrame = serde_json::from_str(&text)?;
687→        match frame {
688→            GatewayFrame::Request(req) => {
689→                if req.method != "connect" {
690→                    anyhow::bail!("first message must be 'connect', got '{}'", req.method);
691→                }
692→                let raw = req.params.unwrap_or(serde_json::Value::Null);
693→
694→                // Try v4 format first (has `protocol` object instead of flat fields).
695→                if let Ok(v4) = serde_json::from_value::<ConnectParamsV4>(raw.clone()) {
696→                    return Ok(ConnectResult {
697→                        request_id: req.id,
698→                        params: v4.into_connect_params(),
699→                        is_v4: true,
700→                    });
701→                }
702→
703→                // Fall back to v3 flat format.
704→                let params: ConnectParams = serde_json::from_value(raw)?;
705→                return Ok(ConnectResult {
706→                    request_id: req.id,
707→                    params,
708→                    is_v4: false,
709→                });
710→            },
711→            _ => anyhow::bail!("first message must be a request frame"),
712→        }
713→    }
714→    anyhow::bail!("connection closed before handshake")
715→}
