370→    /// Launch a browser inside a container (sandboxed mode).
371→    async fn launch_sandboxed_browser(&self, session_id: &str) -> Result<BrowserInstance, Error> {
372→        use crate::container;
373→
374→        // All container operations (CLI checks, image pulls, container start +
375→        // readiness polling) use synchronous `std::process::Command` and
376→        // `std::thread::sleep`.  Run them on the blocking thread-pool so they
377→        // don't stall the tokio event loop.
378→        let image = self.config.sandbox_image.clone();
379→        let prefix = self.config.container_prefix.clone();
380→        let vw = self.config.viewport_width;
381→        let vh = self.config.viewport_height;
382→        let low_mem = self.config.low_memory_threshold_mb;
383→        let session_timeout_ms = browserless_session_timeout_ms(
384→            self.config.idle_timeout_secs,
385→            self.config.navigation_timeout_ms,
386→            MAX_BROWSER_INSTANCE_LIFETIME.as_secs(),
387→        );
388→        let profile_dir = sandbox_profile_dir(self.config.resolved_profile_dir(), session_id);
389→        let container_host = self.config.container_host.clone();
390→
391→        let container = tokio::task::spawn_blocking(move || {
392→            // Check container runtime availability (Docker or Apple Container)
393→            if !container::is_container_available() {
394→                return Err(Error::LaunchFailed(
395→                    "No container runtime available for sandboxed browser. \
396→                     Please install Docker or Apple Container."
397→                        .to_string(),
398→                ));
399→            }
400→
401→            // Ensure the container image is available
402→            let t_image = Instant::now();
403→            container::ensure_image(&image)
404→                .map_err(|e| Error::LaunchFailed(format!("failed to ensure browser image: {e}")))?;
405→            info!(
406→                elapsed_ms = t_image.elapsed().as_millis() as u64,
407→                "browser container image ready"
408→            );
409→
410→            // Create profile directory on host if needed
411→            if let Some(ref dir) = profile_dir
412→                && let Err(e) = std::fs::create_dir_all(dir)
413→            {
414→                warn!(
415→                    path = %dir.display(),
416→                    error = %e,
417→                    "failed to create browser profile directory for container"
418→                );
419→            }
420→
421→            // Start the container (includes readiness polling)
422→            BrowserContainer::start(
423→                &image,
424→                &prefix,
425→                vw,
426→                vh,
427→                low_mem,
428→                session_timeout_ms,
429→                profile_dir.as_deref(),
430→                &container_host,
431→            )
432→            .map_err(|e| Error::LaunchFailed(format!("failed to start browser container: {e}")))
433→        })
434→        .await
435→        .map_err(|e| Error::LaunchFailed(format!("container launch task panicked: {e}")))??;
436→
437→        let ws_url = container.websocket_url();
438→        info!(
439→            session_id,
440→            container_id = container.id(),
441→            ws_url,
442→            "connecting to sandboxed browser"
443→        );
444→
445→        // Connect to the containerized browser with custom timeout
446→        let handler_config = HandlerConfig {
447→            request_timeout: Duration::from_millis(self.config.navigation_timeout_ms),
448→            viewport: Some(chromiumoxide::handler::viewport::Viewport {
449→                width: self.config.viewport_width,
450→                height: self.config.viewport_height,
451→                device_scale_factor: Some(self.config.device_scale_factor),
452→                emulating_mobile: false,
453→                is_landscape: true,
454→                has_touch: false,
455→            }),
456→            ..Default::default()
457→        };
458→
459→        let (browser, mut handler) = Browser::connect_with_config(&ws_url, handler_config)
460→            .await
461→            .map_err(|e| {
462→                Error::LaunchFailed(format!(
463→                    "failed to connect to containerized browser at {}: {}",
464→                    ws_url, e
465→                ))
466→            })?;
467→
468→        // Spawn handler to process browser events
469→        let session_id_clone = session_id.to_string();
470→        tokio::spawn(async move {
471→            while let Some(event) = handler.next().await {
472→                debug!(session_id = session_id_clone, ?event, "browser event");
473→            }
474→            // Handler exits when connection closes - this is normal for idle sessions
475→            debug!(
476→                session_id = session_id_clone,
477→                "sandboxed browser event handler exited (connection closed)"
478→            );
479→        });
480→
481→        info!(session_id, "sandboxed browser connected successfully");
482→
483→        Ok(BrowserInstance {
484→            browser,
485→            pages: HashMap::new(),
486→            last_used: Instant::now(),
487→            created_at: Instant::now(),
488→            sandboxed: true,
489→            container: Some(container),
490→        })
491→    }
492→
493→    /// Launch a browser on the host (non-sandboxed mode).
494→    async fn launch_host_browser(
495→        &self,
496→        session_id: &str,
497→        browser: Option<BrowserPreference>,
498→    ) -> Result<BrowserInstance, Error> {
499→        let requested_browser = browser.unwrap_or_default();
500→
501→        // Detect all installed browser candidates.
502→        let mut detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
503→        let mut install_attempt: Option<crate::detect::AutoInstallResult> = None;
504→
505→        // Auto-install is always on: if none are installed, try to install one.
506→        if detection.browsers.is_empty() {
507→            let result = crate::detect::auto_install_browser(requested_browser).await;
508→            if result.attempted && result.installed {
509→                info!(details = %result.details, "auto-installed browser on host");
510→            } else if result.attempted {
511→                warn!(details = %result.details, "browser auto-install failed");
512→            } else {
513→                warn!(
514→                    details = %result.details,
515→                    "browser auto-install skipped (installer unavailable)"
516→                );
517→            }
518→            install_attempt = Some(result);
519→            detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
520→        }
521→
522→        if detection.browsers.is_empty() {
523→            let mut message = format!("No compatible browser found. {}", detection.install_hint);
524→            if let Some(attempt) = install_attempt
525→                && attempt.attempted
526→            {
527→                message.push_str("\n\nAuto-install attempt:\n");
528→                message.push_str(&attempt.details);
529→            }
530→            return Err(Error::LaunchFailed(message));
531→        }
532→
533→        let selected =
534→            match crate::detect::pick_browser(&detection.browsers, Some(requested_browser)) {
535→                Some(browser) => browser,
536→                None => {
537→                    let installed = crate::detect::installed_browser_labels(&detection.browsers);
538→                    let installed_list = if installed.is_empty() {
539→                        "none".to_string()
540→                    } else {
541→                        installed.join(", ")
542→                    };
543→                    return Err(Error::LaunchFailed(format!(
544→                        "requested browser '{}' is not installed. Installed browsers: {}",
545→                        requested_browser, installed_list
546→                    )));
547→                },
548→            };
549→
550→        let mut builder = CdpBrowserConfig::builder();
551→
552→        // with_head() shows the browser window (non-headless mode)
553→        // By default chromiumoxide runs headless, so we only call with_head() when NOT headless
554→        if !self.config.headless {
555→            builder = builder.with_head();
556→        }
557→
558→        info!(
559→            session_id,
560→            viewport_width = self.config.viewport_width,
561→            viewport_height = self.config.viewport_height,
562→            device_scale_factor = self.config.device_scale_factor,
563→            headless = self.config.headless,
564→            "configuring browser viewport"
565→        );
566→
567→        builder = builder
568→            .viewport(chromiumoxide::handler::viewport::Viewport {
569→                width: self.config.viewport_width,
570→                height: self.config.viewport_height,
571→                device_scale_factor: Some(self.config.device_scale_factor),
572→                emulating_mobile: false,
573→                is_landscape: true,
574→                has_touch: false,
575→            })
576→            .request_timeout(Duration::from_millis(self.config.navigation_timeout_ms));
577→
578→        // User agent can be set via Chrome arg instead of builder method
579→        if let Some(ref ua) = self.config.user_agent {
580→            builder = builder.arg(format!("--user-agent={ua}"));
581→        }
582→        builder = builder.chrome_executable(selected.path.clone());
583→
584→        for arg in &self.config.chrome_args {
585→            builder = builder.arg(arg);
586→        }
587→
588→        // Set persistent profile directory if configured
589→        if let Some(ref profile_path) = self.config.resolved_profile_dir() {
590→            if let Err(e) = std::fs::create_dir_all(profile_path) {
591→                warn!(
592→                    path = %profile_path.display(),
593→                    error = %e,
594→                    "failed to create browser profile directory, falling back to ephemeral"
595→                );
596→            } else {
597→                info!(
598→                    path = %profile_path.display(),
599→                    "using persistent browser profile"
600→                );
601→                builder = builder.user_data_dir(profile_path);
602→            }
603→        }
604→
605→        // Additional security/sandbox args for headless
606→        builder = builder
607→            .arg("--disable-gpu")
608→            .arg("--disable-dev-shm-usage")
609→            .arg("--disable-software-rasterizer")
610→            .arg("--no-sandbox")
611→            .arg("--disable-setuid-sandbox");
612→
613→        // Auto-inject low-memory flags on constrained systems
614→        if self.config.low_memory_threshold_mb > 0 {
615→            let mut sys = System::new();
616→            sys.refresh_memory();
617→            let total_mb = sys.total_memory() / (1024 * 1024);
618→            let extra = low_memory_chrome_args(total_mb, self.config.low_memory_threshold_mb);
619→            if !extra.is_empty() {
620→                info!(
621→                    total_mb,
622→                    threshold = self.config.low_memory_threshold_mb,
623→                    "low memory detected, adding constrained Chrome flags"
624→                );
625→                for arg in extra {
626→                    builder = builder.arg(*arg);
627→                }
628→            }
629→        }
630→
631→        let config = builder
632→            .build()
633→            .map_err(|e| Error::LaunchFailed(format!("failed to build browser config: {e}")))?;
634→
635→        let (browser, mut handler) = Browser::launch(config).await.map_err(|e| {
636→            // Include install instructions in launch failure messages
637→            let install_hint = crate::detect::install_instructions();
638→            Error::LaunchFailed(format!("browser launch failed: {e}\n\n{install_hint}"))
639→        })?;
640→
641→        info!(
642→            session_id,
643→            browser = %selected.kind,
644→            path = %selected.path.display(),
645→            "launched host browser executable"
646→        );
647→
648→        // Spawn handler to process browser events
649→        let session_id_clone = session_id.to_string();
650→        tokio::spawn(async move {
651→            while let Some(event) = handler.next().await {
652→                debug!(session_id = session_id_clone, ?event, "browser event");
653→            }
654→        });
655→
656→        Ok(BrowserInstance {
657→            browser,
658→            pages: HashMap::new(),
659→            last_used: Instant::now(),
660→            created_at: Instant::now(),
661→            sandboxed: false,
662→            container: None,
663→        })
664→    }
665→}
