667→impl Drop for BrowserPool {
668→    fn drop(&mut self) {
669→        let instances = self.instances.get_mut();
670→        let count = instances.len();
671→        if count > 0 {
672→            info!(
673→                count,
674→                "browser pool dropping, stopping remaining containers"
675→            );
676→        }
677→    }
678→}
