680→/// Generate a random session ID.
681→fn generate_session_id() -> String {
682→    use rand::Rng;
683→    let mut rng = rand::rng();
684→    let id: u64 = rng.random();
685→    format!("browser-{:016x}", id)
686→}
687→
688→/// Sanitize a session identifier to a filesystem-safe single path segment.
689→fn sanitize_session_component(session_id: &str) -> String {
690→    let sanitized: String = session_id
691→        .chars()
692→        .map(|ch| match ch {
693→            'a'..='z' | 'A'..='Z' | '0'..='9' | '-' | '_' => ch,
694→            _ => '_',
695→        })
696→        .collect();
697→
698→    if sanitized.is_empty() {
699→        return "session".to_string();
700→    }
701→
702→    sanitized
703→}
704→
705→/// Derive a per-session sandbox profile directory from a configured profile root.
706→fn sandbox_profile_dir(profile_root: Option<PathBuf>, session_id: &str) -> Option<PathBuf> {
707→    profile_root.map(|root| {
708→        root.join("sandbox")
709→            .join(sanitize_session_component(session_id))
710→    })
711→}
