189→impl AgentTool for BrowserTool {
190→    fn name(&self) -> &str {
191→        "browser"
192→    }
193→
194→    fn description(&self) -> &str {
195→        "Control a real browser to interact with web pages.\n\n\
196→         USE THIS TOOL when the user says 'browse', 'browser', 'open in browser', \
197→         or needs interaction (clicking, forms, screenshots, JavaScript-heavy pages).\n\n\
198→         REQUIRED: You MUST specify an 'action' parameter. Example:\n\
199→         {\"action\": \"navigate\", \"url\": \"https://example.com\"}\n\n\
200→         Actions: navigate, screenshot, snapshot, click, type, scroll, evaluate, wait, close\n\n\
201→         BROWSER CHOICE: optionally set \"browser\" to choose one (auto, chrome, chromium, \
202→         edge, brave, opera, vivaldi, arc). If no browser is installed, Moltis will try \
203→         to auto-install one.\n\n\
204→         SESSION: The browser session is automatically tracked per chat session. \
205→         After 'navigate', subsequent actions in the same chat will reuse the same \
206→         browser. No need to pass session_id.\n\n\
207→         WORKFLOW:\n\
208→         1. {\"action\": \"navigate\", \"url\": \"...\"} - opens URL in browser\n\
209→         2. {\"action\": \"snapshot\"} - get interactive elements with ref numbers\n\
210→         3. {\"action\": \"click\", \"ref_\": N} - click element by ref number\n\
211→         4. {\"action\": \"screenshot\"} - capture the current view\n\
212→         5. {\"action\": \"close\"} - close the browser when done"
213→    }
214→
215→    fn parameters_schema(&self) -> serde_json::Value {
216→        serde_json::json!({
217→            "type": "object",
218→            "required": ["action"],
219→            "properties": {
220→                "action": {
221→                    "type": "string",
222→                    "enum": ["navigate", "screenshot", "snapshot", "click", "type", "scroll", "evaluate", "wait", "get_url", "get_title", "back", "forward", "refresh", "close"],
223→                    "description": "REQUIRED. The browser action to perform. Use 'navigate' with 'url' to open a page, 'snapshot' to see elements, 'screenshot' to capture."
224→                },
225→                "session_id": {
226→                    "type": "string",
227→                    "description": "Browser session ID (omit to create new session, or reuse existing)"
228→                },
229→                "browser": {
230→                    "type": "string",
231→                    "enum": ["auto", "chrome", "chromium", "edge", "brave", "opera", "vivaldi", "arc"],
232→                    "description": "Browser to use for host mode. Default: auto (first installed browser)."
233→                },
234→                "url": {
235→                    "type": "string",
236→                    "description": "URL to navigate to (for 'navigate' action)"
237→                },
238→                "ref_": {
239→                    "type": "integer",
240→                    "description": "Element reference number from snapshot (for click/type/scroll)"
241→                },
242→                "text": {
243→                    "type": "string",
244→                    "description": "Text to type (for 'type' action)"
245→                },
246→                "code": {
247→                    "type": "string",
248→                    "description": "JavaScript code to execute (for 'evaluate' action)"
249→                },
250→                "x": {
251→                    "type": "integer",
252→                    "description": "Horizontal scroll pixels (for 'scroll' action)"
253→                },
254→                "y": {
255→                    "type": "integer",
256→                    "description": "Vertical scroll pixels (for 'scroll' action)"
257→                },
258→                "full_page": {
259→                    "type": "boolean",
260→                    "description": "Capture full page screenshot vs viewport only"
261→                },
262→                "selector": {
263→                    "type": "string",
264→                    "description": "CSS selector to wait for (for 'wait' action)"
265→                },
266→                "timeout_ms": {
267→                    "type": "integer",
268→                    "description": "Timeout in milliseconds (default: 60000)"
269→                }
270→            }
271→        })
272→    }
273→
274→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
275→        let mut params = params;
276→
277→        // Browser sandbox mode follows the session sandbox mode from the shared router.
278→        let session_key = Self::cache_key(params.get("_session_key").and_then(|v| v.as_str()));
279→        let sandbox_mode = if let Some(ref router) = self.sandbox_router {
280→            router.is_sandboxed(&session_key).await
281→        } else {
282→            debug!(
283→                session_key = %session_key,
284→                "browser running in host mode (no container backend)"
285→            );
286→            false
287→        };
288→
289→        // Inject saved session_id if LLM didn't provide one (or provided empty string)
290→        if let Some(obj) = params.as_object_mut() {
291→            let needs_session = match obj.get("session_id") {
292→                None => true,
293→                Some(serde_json::Value::String(s)) if s.is_empty() => true,
294→                Some(serde_json::Value::Null) => true,
295→                _ => false,
296→            };
297→
298→            if needs_session && let Some(saved_sid) = self.get_saved_session(&session_key).await {
299→                debug!(
300→                    session_key = %session_key,
301→                    session_id = %saved_sid,
302→                    "injecting saved session_id (LLM didn't provide one)"
303→                );
304→                obj.insert("session_id".to_string(), serde_json::json!(saved_sid));
305→            }
306→
307→            // Inject sandbox mode from session context
308→            obj.insert("sandbox".to_string(), serde_json::json!(sandbox_mode));
309→        }
310→
311→        // Check if this is a "close" action - we'll clear saved session after
312→        let is_close = params
313→            .get("action")
314→            .and_then(|a| a.as_str())
315→            .is_some_and(|a| a == "close");
316→
317→        // Try to parse the request, defaulting to "navigate" if action is missing
318→        let request: BrowserRequest = match serde_json::from_value(params.clone()) {
319→            Ok(req) => req,
320→            Err(e) if e.to_string().contains("missing field `action`") => {
321→                // Default to navigate action if action is missing but url is present
322→                if let Some(obj) = params.as_object_mut() {
323→                    if obj.contains_key("url") {
324→                        obj.insert("action".to_string(), serde_json::json!("navigate"));
325→                        serde_json::from_value(params)?
326→                    } else {
327→                        // No URL either - return helpful error
328→                        return Err(Error::message(
329→                            "Missing required 'action' field. Use: \
330→                             {\"action\": \"navigate\", \"url\": \"https://...\"} to open a page",
331→                        )
332→                        .into());
333→                    }
334→                } else {
335→                    return Err(e.into());
336→                }
337→            },
338→            Err(e) => return Err(e.into()),
339→        };
340→
341→        let manager = self.manager().await;
342→        let response = manager.handle_request(request).await;
343→
344→        // Track the session ID for future reuse
345→        if response.success {
346→            if is_close {
347→                self.clear_session(&session_key).await;
348→            } else {
349→                self.save_session(&session_key, &response.session_id).await;
350→            }
351→        }
352→
353→        Ok(serde_json::to_value(&response)?)
354→    }
355→
356→    async fn warmup(&self) -> anyhow::Result<()> {
357→        let started = std::time::Instant::now();
358→        let _ = self.manager().await;
359→        debug!(
360→            elapsed_ms = started.elapsed().as_millis(),
361→            "browser tool warmup complete"
362→        );
363→        Ok(())
364→    }
365→}
