112→function upsertSessionFromEvent(entry) {
113→	if (!entry?.key) return false;
114→	sessionStore.upsert(entry);
115→	var legacy = S.sessions.slice();
116→	var idx = legacy.findIndex((session) => session.key === entry.key);
117→	if (idx >= 0) {
118→		legacy[idx] = { ...legacy[idx], ...entry };
119→	} else {
120→		legacy.push({ ...entry });
121→	}
122→	S.setSessions(legacy);
123→	renderSessionList();
124→	return true;
125→}
