 2→//! Install / manage a headless node as an OS service.
 3→//!
 4→//! - **macOS**: launchd user agent (`~/Library/LaunchAgents/org.moltis.node.plist`)
 5→//! - **Linux**: systemd user unit (`~/.config/systemd/user/moltis-node.service`)
 6→//!
 7→//! The service wraps `moltis node run` with the persisted connection parameters.
 8→
 9→use std::{
10→    fs,
11→    path::{Path, PathBuf},
12→    process::Command,
13→};
14→
15→use {
16→    serde::{Deserialize, Serialize},
17→    tracing::{debug, info},
18→};
19→
20→// ── Persisted connection config ────────────────────────────────────────────
21→
22→/// Connection parameters saved to `~/.moltis/node.json` so the service can
23→/// start without CLI flags.
24→#[derive(Debug, Clone, Serialize, Deserialize)]
25→pub struct ServiceConfig {
26→    pub gateway_url: String,
27→    pub device_token: String,
28→    #[serde(skip_serializing_if = "Option::is_none")]
29→    pub node_id: Option<String>,
30→    #[serde(skip_serializing_if = "Option::is_none")]
31→    pub display_name: Option<String>,
32→    #[serde(skip_serializing_if = "Option::is_none")]
33→    pub working_dir: Option<String>,
34→    #[serde(default = "default_timeout")]
35→    pub timeout: u64,
36→}
37→
38→fn default_timeout() -> u64 {
39→    300
40→}
41→
42→impl ServiceConfig {
43→    /// Load from `<data_dir>/node.json`.
44→    pub fn load(data_dir: &Path) -> anyhow::Result<Self> {
45→        let path = data_dir.join("node.json");
46→        let contents = fs::read_to_string(&path)
47→            .map_err(|e| anyhow::anyhow!("cannot read {}: {e}", path.display()))?;
48→        let config: Self = serde_json::from_str(&contents)?;
49→        Ok(config)
50→    }
51→
52→    /// Save to `<data_dir>/node.json`.
53→    pub fn save(&self, data_dir: &Path) -> anyhow::Result<()> {
54→        fs::create_dir_all(data_dir)?;
55→        let path = data_dir.join("node.json");
56→        let json = serde_json::to_string_pretty(self)?;
57→        fs::write(&path, json)?;
58→        info!(path = %path.display(), "saved node config");
59→        Ok(())
60→    }

