 65→/// Detect installed runtimes using `which`.
 66→fn detect_runtimes() -> Vec<String> {
 67→    let candidates = ["python3", "python", "node", "ruby", "go", "rustc", "java"];
 68→    let mut found = Vec::new();
 69→    for name in candidates {
 70→        // Skip "python" if we already found "python3".
 71→        if name == "python" && found.contains(&"python3".to_string()) {
 72→            continue;
 73→        }
 74→        if which::which(name).is_ok() {
 75→            found.push(name.to_string());
 76→        }
 77→    }
 78→    found
 79→}
