 81→/// Collect system telemetry using `sysinfo`.
 82→fn collect_system_telemetry(node_id: &str) -> serde_json::Value {
 83→    use sysinfo::{Disks, System};
 84→
 85→    let mut sys = System::new();
 86→    sys.refresh_memory();
 87→    sys.refresh_cpu_all();
 88→
 89→    let uptime = System::uptime();
 90→
 91→    // Disk: find the root partition.
 92→    let disks = Disks::new_with_refreshed_list();
 93→    let root_disk = disks
 94→        .iter()
 95→        .find(|d| d.mount_point() == std::path::Path::new("/"));
 96→    let disk_total = root_disk.map(|d| d.total_space());
 97→    let disk_available = root_disk.map(|d| d.available_space());
 98→
 99→    let runtimes = detect_runtimes();
100→
101→    serde_json::json!({
102→        "nodeId": node_id,
103→        "mem": {
104→            "total": sys.total_memory(),
105→            "available": sys.available_memory(),
106→        },
107→        "cpuCount": sys.cpus().len(),
108→        "cpuUsage": sys.global_cpu_usage(),
109→        "uptime": uptime,
110→        "services": [],
111→        "disk": {
112→            "total": disk_total,
113→            "available": disk_available,
114→        },
115→        "runtimes": runtimes,
116→    })
117→}
