fn save_soul_for_agent_writes_to_agent_dir() {
    let _guard = DATA_DIR_TEST_LOCK.lock().unwrap();
    let dir = tempfile::tempdir().expect("tempdir");
    set_data_dir(dir.path().to_path_buf());

    let custom = "Agent soul content.";
