#[test]
fn share_dir_override_takes_precedence() {
    let dir = tempfile::tempdir().expect("tempdir");
    set_share_dir(dir.path().to_path_buf());

    let result = share_dir();
    assert_eq!(result, Some(dir.path().to_path_buf()));

